function organizarPastasWMGJ() {
  registrarLog("Iniciando verificação da estrutura de pastas...");
  try {
    const chavesPastas = Object.keys(CONFIG.folders);
    let pastasCriadasOuVerificadas = 0;

    chavesPastas.forEach(chave => {
      const id = CONFIG.folders[chave];
      if (id) {
        DriveApp.getFolderById(id); // Apenas testa se a pasta existe e está acessível
        pastasCriadasOuVerificadas++;
      }
    });
    registrarLog("Pastas verificadas com sucesso: " + pastasCriadasOuVerificadas);
  } catch (erro) {
    registrarLog("ERRO_ORGANIZAR_PASTAS: " + erro.message);
  }
}

function organizarArquivosAvancadoWMGJ() {
  registrarLog("Iniciando triagem avançada de arquivos...");
  try {
    const pastaBruta = DriveApp.getFolderById(CONFIG.folders.bruto);
    const arquivos = pastaBruta.getFiles();
    let count = 0;

    while (arquivos.hasNext()) {
      const arquivo = arquivos.next();
      const nome = arquivo.getName().toLowerCase();

      // Exemplo de roteamento básico (será substituído pelo Gemini na Fase 4)
      if (nome.includes("recibo") || nome.includes("nf")) {
        arquivo.moveTo(DriveApp.getFolderById(CONFIG.folders.financeiro));
      } else if (nome.includes("contrato")) {
        arquivo.moveTo(DriveApp.getFolderById(CONFIG.folders.contratos));
      } else {
        arquivo.moveTo(DriveApp.getFolderById(CONFIG.folders.staging));
      }
      count++;
    }
    registrarLog("Arquivos roteados: " + count);
  } catch (erro) {
    registrarLog("ERRO_ORGANIZAR_ARQUIVOS: " + erro.message);
  }
}

function atualizarDashboard() {
  registrarLog("Consolidando dados para o Dashboard Base...");
