    if (!sheetDash) throw new Error("Aba de Dashboard não encontrada.");

    // Atualiza a data da última sincronização
    sheetDash.getRange("A1").setValue("Última Atualização:");
    sheetDash.getRange("B1").setValue(new Date());

    registrarLog("Dashboard atualizado.");
  } catch (erro) {
    registrarLog("ERRO_ATUALIZAR_DASHBOARD: " + erro.message);
  }
}

