function myFunction() {function auditoriaCompletaWMGJ() {
  const raiz = DriveApp.getFolderById(CONFIG.PASTA_DRIVE_ID);

  let relatorio = [];

  relatorio.push("🔍 AUDITORIA WMGJ");
  relatorio.push("Data: " + new Date());
  relatorio.push("------------------------");

  // 1. Verificar pastas obrigatórias
  const obrigatorias = [
    "01_ENTRADA_DOCUMENTOS",
    "02_FINANCEIRO",
    "03_PRODUTIVIDADE",
    "04_RELATORIOS",
    "05_GLOSAS",
    "07_BACKUP"
  ];

  const pastas = {};
  const it = raiz.getFolders();

  while (it.hasNext()) {
    const p = it.next();
    pastas[p.getName()] = true;
  }

  obrigatorias.forEach(p => {
    if (!pastas[p]) {
      relatorio.push("❌ Pasta faltando: " + p);
    } else {
      relatorio.push("✅ Pasta OK: " + p);
    }
  });

  // 2. Verificar arquivos na raiz (erro comum)
  const arquivosRaiz = raiz.getFiles();
  let countRaiz = 0;

  while (arquivosRaiz.hasNext()) {
    arquivosRaiz.next();
    countRaiz++;
  }

  if (countRaiz > 0) {
    relatorio.push("⚠️ Arquivos soltos na raiz: " + countRaiz);
  } else {
    relatorio.push("✅ Sem arquivos soltos");
  }

  // 3. Verificar nomes fora do padrão
  const arquivos = raiz.getFiles();
  while (arquivos.hasNext()) {
    const file = arquivos.next();
    const nome = file.getName();

    if (!nome.startsWith("PROC_") && !nome.startsWith("AUTO_")) {
      relatorio.push("⚠️ Nome fora do padrão: " + nome);
    }
  }

  // 4. Verificar tamanho dos arquivos (risco OCR)
  const arquivos2 = raiz.getFiles();
  while (arquivos2.hasNext()) {
    const file = arquivos2.next();

    if (file.getSize() > 5 * 1024 * 1024) {
      relatorio.push("⚠️ Arquivo grande (OCR pode falhar): " + file.getName());
    }
  }

  salvarRelatorioAuditoria(relatorio.join("\n"));

  Logger.log(relatorio.join("\n"));
}

}

const GOVERNANCA = {
  PASTA_RAIZ_ID: "1womnmIbaNQ8qkNlnkS2Ni71LVwtdrNj5",
  SPREADSHEET_ID: "15LgI2U2dtM7vnrxFsiQMPTvBapBDg5ftgGttx7Pw0Cw"
};function organizarPastasWMGJ() {
  const pastaRaiz = DriveApp.getFolderById(GOVERNANCA.PASTA_RAIZ_ID);

  const estruturaPadrao = [
    "00_GOVERNANCA",
    "01_ENTRADA_DOCUMENTOS",
    "02_FINANCEIRO",
    "03_PRODUTIVIDADE",
    "04_RELATORIOS",
    "05_GLOSAS",
    "06_CONTRATOS",
    "07_BACKUP"
  ];

  const pastasExistentes = {};
  const it = pastaRaiz.getFolders();

  // mapear pastas existentes
  while (it.hasNext()) {
    const p = it.next();
    pastasExistentes[p.getName()] = p;
  }

  estruturaPadrao.forEach(nome => {

    // se já existe corretamente → ok
    if (pastasExistentes[nome]) return;

    // tentar encontrar pasta semelhante para renomear
    const similar = Object.keys(pastasExistentes).find(p =>
      p.toLowerCase().includes(nome.split("_")[1]?.toLowerCase() || "")
    );

    if (similar) {
      pastasExistentes[similar].setName(nome);
      registrarLog("PASTA_RENOMEADA_" + similar + "_PARA_" + nome);
    } else {
      pastaRaiz.createFolder(nome);
      registrarLog("PASTA_CRIADA_" + nome);
    }
  });
}

