function myFunction() {function organizarArquivosAvancadoWMGJ() {
  const raiz = DriveApp.getFolderById(CONFIG.PASTA_DRIVE_ID);
  const pastas = mapearPastas(raiz);

  const arquivos = raiz.getFiles();

  while (arquivos.hasNext()) {
    const file = arquivos.next();

    // ignora arquivos já organizados
    if (file.getName().startsWith("ORG_")) continue;

    const classificacao = classificarArquivo(file);

    if (!classificacao || !pastas[classificacao]) {
      registrarLog("NAO_CLASSIFICADO_" + file.getName());
      continue;
    }

    try {
      pastas[classificacao].addFile(file);
      raiz.removeFile(file);

      file.setName("ORG_" + file.getName());

      registrarLog("MOVIDO_" + file.getName() + "_PARA_" + classificacao);

    } catch (e) {
      registrarLog("ERRO_MOVER_" + file.getName());
    }
  }
}

}

