function atualizarDashboardFinanceiro() {
  const ss = getPlanilha();

  let dashboard = ss.getSheetByName("05_DASHBOARD");
  if (!dashboard) dashboard = ss.insertSheet("05_DASHBOARD");

  const resultado = ss.getSheetByName("03_RESULTADO_FINANCEIRO");
  const classificado = ss.getSheetByName("02_EXTRATO_CLASSIFICADO");

  dashboard.clear();

  dashboard.appendRow(["PAINEL FINANCEIRO WMGJ"]);
  dashboard.appendRow(["Última atualização", new Date()]);
  dashboard.appendRow([""]);

  if (resultado && resultado.getLastRow() > 1) {
    const dadosResultado = resultado.getDataRange().getValues();

    dashboard.appendRow(["INDICADOR", "VALOR"]);

    for (let i = 1; i < dadosResultado.length; i++) {
      dashboard.appendRow(dadosResultado[i]);
    }
  }

  dashboard.appendRow([""]);

  if (classificado && classificado.getLastRow() > 1) {
    const dados = classificado.getDataRange().getValues();

    let totalLancamentos = dados.length - 1;
    let desconhecidos = 0;
    let receitas = 0;
    let despesas = 0;

    for (let i = 1; i < dados.length; i++) {
      const valor = Number(dados[i][5]) || 0;
      const categoria = dados[i][8];

      if (categoria === "desconhecido") desconhecidos++;
      if (valor > 0) receitas += valor;
      if (valor < 0) despesas += Math.abs(valor);
    }

    dashboard.appendRow(["RESUMO OPERACIONAL", "VALOR"]);
    dashboard.appendRow(["Total de lançamentos", totalLancamentos]);
    dashboard.appendRow(["Lançamentos desconhecidos", desconhecidos]);
    dashboard.appendRow(["Receitas detectadas", receitas]);
    dashboard.appendRow(["Despesas detectadas", despesas]);
  }

  Logger.log("DASHBOARD_ATUALIZADO");
}

