function processarArquivosIME() {
  const pasta = DriveApp.getFolderById(CONFIG.PASTA_ENTRADA);
  const arquivos = pasta.getFiles();
  const ss = SpreadsheetApp.openById(CONFIG.SPREADSHEET_ID);

  const abaFinanceiro = ss.getSheetByName("05_FINANCEIRO_MENSAL");
  const abaProd = ss.getSheetByName("02_PRODUTIVIDADE_MENSAL");

  while (arquivos.hasNext()) {
    const file = arquivos.next();
    const nome = file.getName();

    // 🔍 Extração simples (ajustável depois com IA)
    const texto = file.getBlob().getDataAsString();

    const valorMatch = texto.match(/R\$ ?([\d.,]+)/);
    const atendMatch = texto.match(/(\d+) atendimentos/);

    const valor = valorMatch ? parseFloat(valorMatch[1].replace(",", ".")) : 0;
    const atend = atendMatch ? parseInt(atendMatch[1]) : 0;

    const data = new Date();
    const competencia = Utilities.formatDate(data, "GMT-3", "yyyy-MM");

    // 💰 Financeiro
    abaFinanceiro.appendRow([
      competencia,
      competencia,
      "HOSPITAL",
      "CARDIOLOGIA",
      valor,
      valor,
      0,
      valor,
      0,
      0,
      valor,
      "Importado automático"
    ]);

    // 🏥 Produção
    abaProd.appendRow([
      competencia,
      "HOSPITAL",
      "CARDIOLOGIA",
      atend,
